// ─── FIREBASE INIT ────────────────────────────────────────────────
firebase.initializeApp({projectId:"aria-training",databaseURL:"https://aria-training-default-rtdb.firebaseio.com"});
var db=firebase.database();
var UID="brandon";
async function dbGet(key){try{const snap=await db.ref(UID+"/"+key).get();return snap.exists()?{value:snap.val()}:null;}catch(e){try{const v=localStorage.getItem(key);return v?{value:v}:null;}catch{return null;}}}
async function dbSet(key,data){const str=JSON.stringify(data);try{await db.ref(UID+"/"+key).set(str);}catch(e){try{localStorage.setItem(key,str);}catch{}}}

