// ─── RULES ENGINE ─────────────────────────────────────────────────
function analyze(week,plan,runs,strength,hr,nutrition){
  const warnings=[],positives=[],actions=[];
  const W=(t,b,s)=>warnings.push({t,b,s});
  const P=(t,b)=>positives.push({t,b});
  const A=(p,t)=>actions.push({p,t});
  const wkRuns=runs.filter(r=>r.week===week&&isRunActivity(r.type));
  const wkMi=wkRuns.reduce((a,r)=>a+parseFloat(r.dist||0),0);
  const wkStr=strength.filter(s=>s.week===week);
  const l7hr=hr.slice(0,14);
  const restHRs=l7hr.filter(h=>h.resting).map(h=>h.resting);
  const hrvVals=l7hr.filter(h=>h.hrv).map(h=>h.hrv);
  const avgRest=restHRs.length?Math.round(restHRs.reduce((a,b)=>a+b,0)/restHRs.length):null;
  const avgHRV=hrvVals.length?Math.round(hrvVals.reduce((a,b)=>a+b,0)/hrvVals.length):null;
  const pct=plan.miles>0?(wkMi/plan.miles)*100:0;
  if(wkRuns.length>0){
    if(pct>=90)P("Volume on track",`${wkMi.toFixed(1)} of ${plan.miles} planned miles (${Math.round(pct)}%). Executing the plan.`);
    else if(pct<50&&!plan.recovery)W("Volume behind",`${wkMi.toFixed(1)} of ${plan.miles} miles. ${(plan.miles-wkMi).toFixed(1)}mi remaining.`,"Don't double up — stick to plan.");
  }
  wkRuns.filter(r=>!["tempo","intervals","long_run"].includes(r.type)).forEach(r=>{if(r.hrAvg&&+r.hrAvg>155)W("Easy run HR too high",`${r.date}: ${r.hrAvg}bpm on easy run.`,"Zone 2 ceiling is 143bpm. Slow down to build aerobic base.");});
  if(restHRs.length>=3){
    const r3=restHRs.slice(0,3).reduce((a,b)=>a+b,0)/3,o3=restHRs.slice(3,6).length?restHRs.slice(3,6).reduce((a,b)=>a+b,0)/restHRs.slice(3,6).length:r3;
    if(r3>o3+5){W("Resting HR elevated",`Up ~${Math.round(r3-o3)}bpm over the past week.`,"Check sleep and nutrition — may indicate incomplete recovery.");A(1,"Prioritize sleep and nutrition — resting HR elevated");}
    else if(r3<o3-5)P("Resting HR improving",`Down ~${Math.round(o3-r3)}bpm — aerobic base building. Fitness is coming.`);
  }
  if(hrvVals.length>=3){
    const r3=hrvVals.slice(0,3).reduce((a,b)=>a+b,0)/3,o3=hrvVals.slice(3,6).length?hrvVals.slice(3,6).reduce((a,b)=>a+b,0)/hrvVals.slice(3,6).length:r3;
    if(r3<o3-5){W("HRV declining",`${Math.round(o3)}→${Math.round(r3)}ms over 7 days.`,"Consider replacing next interval session with easy run.");A(1,"HRV dropping — swap Thursday intervals for easy run if declining further");}
    else if(r3>o3+5)P("HRV trending up",`${Math.round(o3)}→${Math.round(r3)}ms — recovering well. Adaptation is working.`);
  }
  if(wkStr.length>=2)P("Strength on track",`${wkStr.length} sessions logged this week. Injury prevention and running economy are building.`);
  else if(wkStr.length===0&&week>1){W("No strength sessions","Plan calls for 3 sessions (Mon/Wed/Fri).","Strength training cuts injury risk 50%. Prioritize this week.");A(1,"Log at least 2 strength sessions this week");}
  const recentNu=nutrition.slice(0,7);
  if(recentNu.length>=3){
    const under=recentNu.filter(n=>n.calories<NT[n.dayType].calLow).length;
    const lowProt=recentNu.filter(n=>n.protein&&n.protein<NT[n.dayType].protLow).length;
    if(under>=2){W("Chronically underfueling",`${under} of last ${recentNu.length} days below calorie target.`,"Under-fueling impairs recovery and increases injury risk (RED-S).");A(1,"Set 12pm lunch alarm — hit 600-800cal minimum at midday");}
    if(lowProt>=2){W("Protein consistently low",`${lowProt} of last ${recentNu.length} days below protein target.`,"Add a protein shake post-workout — 20-40g within 60 min.");A(2,"Add post-workout protein shake daily");}
    const runDays=recentNu.filter(n=>n.dayType==="run");
    if(runDays.length>=2){const avg=runDays.reduce((a,b)=>a+b.calories,0)/runDays.length;if(avg>=NT.run.calLow&&avg<=NT.run.calHigh+100)P("Run-day fueling on point",`Averaging ${Math.round(avg)}cal on run days — right in the ${NT.run.cal} target. Glycogen levels are set for performance.`);}
  }
  let score=10,factors=[];
  if(restHRs.length>=3){const r3=restHRs.slice(0,3).reduce((a,b)=>a+b,0)/3,o3=restHRs.slice(3,6).length?restHRs.slice(3,6).reduce((a,b)=>a+b,0)/restHRs.slice(3,6).length:r3;if(r3>o3+5){score-=2;factors.push("HR ↑");}}
  if(hrvVals.length>=3){const r3=hrvVals.slice(0,3).reduce((a,b)=>a+b,0)/3,o3=hrvVals.slice(3,6).length?hrvVals.slice(3,6).reduce((a,b)=>a+b,0)/hrvVals.slice(3,6).length:r3;if(r3<o3-5){score-=2;factors.push("HRV ↓");}}
  if(recentNu.length>=2&&recentNu.filter(n=>n.calories<NT[n.dayType].calLow).length>=2){score-=2;factors.push("Underfueling");}
  if(wkMi<plan.miles*0.5&&!plan.recovery&&week>1){score-=1;factors.push("Low volume");}
  if(wkStr.length===0&&week>1){score-=1;factors.push("No strength");}
  const totalRuns=wkRuns.length;
  let summary="";
  if(totalRuns===0&&wkStr.length===0){summary="No workouts logged yet this week. Start logging to track your progress.";}
  else{const parts=[];if(totalRuns>0)parts.push(`${totalRuns} run${totalRuns>1?"s":""} totaling ${wkMi.toFixed(1)} miles`);if(wkStr.length>0)parts.push(`${wkStr.length} strength session${wkStr.length>1?"s":""}`);if(recentNu.length>0)parts.push(`nutrition logged for ${recentNu.length} day${recentNu.length>1?"s":""}`);summary=`This week: ${parts.join(", ")}. ${positives.length>0?positives[0].b:warnings.length>0?warnings[0].b:"Keep executing the plan."}`;}
  return{warnings,positives,actions,score:Math.max(1,Math.min(10,score)),factors,avgRest,avgHRV,wkMi,wkStr,wkRuns,summary};
}

// ─── HELPERS ─────────────────────────────────────────────────────
const getWeek=()=>{try{const w=Math.floor((new Date()-PLAN_START)/(7*24*60*60*1000))+1;return Math.max(1,Math.min(23,w));}catch(e){return 1;}};
const getDTR=()=>Math.max(0,Math.ceil((RACE_DATE-new Date())/(24*60*60*1000)));
const toDay=()=>{const n=new Date();return n.getFullYear()+"-"+String(n.getMonth()+1).padStart(2,"0")+"-"+String(n.getDate()).padStart(2,"0");};
const greet=()=>{const h=new Date().getHours();return h<12?"morning":h<18?"afternoon":"evening";};
const parseGarmin=t=>({
  dist:t.match(/(\d+\.?\d*)\s*mi(?!n)/i)?.[1]||null,
  pace:t.match(/(\d+:\d{2})\s*\/mi/i)?.[1]||null,
  time:t.match(/(?:elapsed|time)[:\s]*(\d+:\d{2}(?::\d{2})?)/i)?.[1]||null,
  hrAvg:t.match(/avg\s*(?:hr|heart)[:\s]*(\d+)/i)?.[1]||t.match(/(\d{2,3})\s*bpm/i)?.[1]||null,
  hrMax:t.match(/max\s*(?:hr|heart)[:\s]*(\d+)/i)?.[1]||null,
  hrRec:t.match(/recov\w*[:\s]*(\d+)/i)?.[1]||null,
  cal:t.match(/(\d+)\s*cal/i)?.[1]||null,
  cad:t.match(/(\d+)\s*spm|cadence[:\s]*(\d+)/i)?.[1]||null
});
const parseCSV=text=>{
  const lines=text.trim().split("\n").filter(l=>l.trim());if(lines.length<2)return[];
  const hdrs=lines[0].split(",").map(h=>h.trim().replace(/"/g,"").toLowerCase());
  return lines.slice(1).map(line=>{
    const vals=line.split(",").map(v=>v.trim().replace(/"/g,""));const row={};hdrs.forEach((h,j)=>row[h]=vals[j]||"");
    const dr=row["date"]||row["start time"]||row["activity date"]||"";const date=dr.split(" ")[0];if(!date)return null;
    const aw=Math.floor((new Date(date+"T00:00:00")-PLAN_START)/(7*24*60*60*1000));const actWeek=(aw<0||aw>=161)?null:Math.max(1,Math.min(23,aw+1));
    return{date,week:actWeek,dist:(row["distance"]||"").replace(/[^\d.]/g,"")||null,pace:row["avg pace"]||null,time:row["time"]||row["elapsed time"]||null,hrAvg:row["avg hr"]||row["average heart rate (bpm)"]||null,hrMax:row["max hr"]||null,cal:row["calories"]||null,type:classifyGarminType(row["activity type"]||""),raw:"Garmin CSV",hrRec:null};
  }).filter(Boolean);
};
function getPlannedForDate(date){
  const d=new Date(date+"T00:00:00");
  const diff=Math.floor((d-PLAN_START)/(7*24*60*60*1000));
  if(diff<0||diff>=23*7)return{week:null,plan:null,runLabel:null,runType:null,strWkt:null,strLabel:null,dow:d.getDay()};
  const wk=Math.max(1,Math.min(23,diff+1));
  const dow=d.getDay();
  const dp=DAY_PLAN(wk);
  const dayPlan=dp.find(p=>p.dow===dow)||{};
  return{week:wk,plan:PLAN[wk]||null,runLabel:dayPlan.runLabel||null,runType:dayPlan.runType||null,strWkt:dayPlan.strWkt||null,strLabel:dayPlan.strLabel||null,dow};
}
